/**
 * Provider ABI — Zod schemas + inferred TypeScript types.
 *
 * Mirrors `warlog_spec.provider_abi` in the Python package. Each Zod
 * schema is the runtime validator AND the type source ; consumers
 * derive the static type via `z.infer<typeof Schema>` (re-exported as
 * a separate `type` alias here for ergonomics).
 *
 * Wire format : camelCase (matches the JSON Schemas generated by the
 * Python backend). All optional fields use `.nullable().optional()`
 * to match Pydantic's `Field(default=None)` behaviour exactly.
 */

import { z } from "zod";

import {
  ComplianceScope,
  type ComplianceScopeValue,
  SelectorRepresentation,
  type SelectorRepresentationValue,
} from "./enums.js";

export const ABI_VERSION = "1.0";
const HEX64_RE = /^[0-9a-f]{64}$/;
const HEX_RE = /^[0-9a-f]+$/;
const HEX64_MESSAGE = "must be lowercase hex sha256 (64 chars)";

// ============================================================================
// Response action catalog — 49 canonical actions
// ============================================================================

