  "host.unisolate",
  "host.restart",
  "host.collect_artifacts",
  "host.stop",
  "host.start",
  "host.delete",
  "process.kill",
  "process.suspend",
  "file.quarantine",
  "file.delete",
  "hash.block",
  "hash.unblock",
  // Network family
  "ip.block",
  "ip.unblock",
  "domain.block",
  "domain.unblock",
  "url.block",
  "url.unblock",
  "session.terminate",
  // Email family
  "email.quarantine",
  "email.recall",
  "email.block_sender",
  "email.unblock_sender",
  "email.release",
  // Identity family
  "user.disable",
  "user.force_logout",
  "user.reset_mfa",
  "user.revoke_tokens",
  "user.reset_password",
  "user.expire_password",
  "user.unlock",
  "user.group_remove",
  "user.delete",
  // PKI
  "cert.revoke",
  // IAM family
  "iam.role_detach",
  "iam.role_attach",
  "iam.credentials_disable",
  "iam.credentials_enable",
  "iam.credentials_rotate",
  // Key / secret family
  "key.disable",
  "key.enable",
  "key.rotate",
  "key.schedule_deletion",
  // Storage family
  "bucket.lockdown",
  "bucket.unlock",
  // Platform / case management
  "alert.acknowledge",
  "case.update_status",
  "playbook.trigger",
